using System.Text.Json; class Program { static void Main() { try { var json = System.IO.File.ReadAllText(System.IO.Path.Combine(System.Environment.GetFolderPath(System.Environment.SpecialFolder.ApplicationData), "LibraryOfAiLexandria", "brain", "settings.json")); var opts = new JsonSerializerOptions { PropertyNameCaseInsensitive = true }; var obj = JsonSerializer.Deserialize<MyClass>(json, opts); System.Console.WriteLine("SUCCESS: " + obj.NovelAiKey); } catch(System.Exception e) { System.Console.WriteLine("ERROR: " + e.Message); } } } class MyClass { public string NovelAiKey { get; set; } }
